then.script:
var payload = mc.getPayloadJSON();
// Equivalent of payload[0] - "_id"
var resp = payload.data[0];
// Remove _id field
if (resp._id !== undefined) {
    delete resp._id;
}
var response = {
    paymentIntentid: resp.paymentIntentid,
    transactionId: resp.transactionId,
    amountReceived: resp.amountReceived,
    currency: resp.currency,
    captureMethod: resp.captureMethod,
    confirmation_method: resp.confirmation_method,
    created: resp.created 
        ? new Date(resp.created.$date).toISOString().split('.')[0] + "Z" 
        : null,
    paymentMethod: resp.paymentMethod,
    status: resp.status
};

// Conditional fields
if (resp.policyNumber != null && resp.policyNumber != undefined) {
    response.policyNumber = resp.policyNumber;
}

if (resp.quoteId != null && resp.quoteId != undefined) {
    response.quoteId = resp.quoteId;
}

if (resp.partyIdentifier != null && resp.partyIdentifier != undefined) {
    response.partyIdentifier = resp.partyIdentifier;
}

// Set final response
mc.setPayloadJSON(response);
